window.addEventListener("load", e => { const t = document.querySelector("#shortInfo"), n = document.createElement("div"), a = document.createElement("a"), r = String(moment().diff("1999-07-30", "years")); a.href = "../static/resume.pdf", a.target = "_blank", a.text = "read curriculum vitae", n.textContent = `${r} years old · santa amélia, paraná, brasil`, t.appendChild(n), t.appendChild(a) });